1977	describe('Spider — variable resolution', () => {
1978	  afterEach(() => {
1979	    clearGuild();
1980	  });
1981	
1982	  it('$writ resolves to the full WritDoc object', async () => {
1983	    const template: RigTemplate = {
1984	      engines: [{ id: 'only', designId: 'seal', givens: { w: '$writ' } }],
1985	    };
1986	    const fix = buildFixture({ spider: { rigTemplates: { default: template } } });
1987	    const { clerk, spider, stacks } = fix;
1988	
1989	    const writ = await clerk.post({ title: 'My writ', body: 'test body' });
1990	    await spider.crawl();
1991	
1992	    const rigs = await rigsBook(stacks).list();
1993	    const engine = rigs[0].engines[0];
1994	    const resolvedWrit = engine.givensSpec.w as { id: string; type: string; title: string };
1995	    assert.equal(resolvedWrit.id, writ.id);
1996	    assert.equal(resolvedWrit.title, writ.title);
1997	  });
1998	
1999	  it('$role resolves to spiderConfig.role when set', async () => {
2000	    const template: RigTemplate = {
2001	      engines: [{ id: 'only', designId: 'seal', givens: { r: '$role' } }],
2002	    };
2003	    const fix = buildFixture({ spider: { role: 'builder', rigTemplates: { default: template } } });
2004	    const { clerk, spider, stacks } = fix;
2005	
2006	    await clerk.post({ title: 'test', body: 'test' });
2007	    await spider.crawl();
2008	
2009	    const rigs = await rigsBook(stacks).list();
2010	    assert.equal(rigs[0].engines[0].givensSpec.r, 'builder');
2011	  });
2012	
2013	  it('$role defaults to "artificer" when spiderConfig.role is not set', async () => {
2014	    const template: RigTemplate = {
2015	      engines: [{ id: 'only', designId: 'seal', givens: { r: '$role' } }],
2016	    };
2017	    const fix = buildFixture({ spider: { rigTemplates: { default: template } } });
2018	    const { clerk, spider, stacks } = fix;
2019	
2020	    await clerk.post({ title: 'test', body: 'test' });
2021	    await spider.crawl();
2022	
2023	    const rigs = await rigsBook(stacks).list();
2024	    assert.equal(rigs[0].engines[0].givensSpec.r, 'artificer');
2025	  });
2026	
2027	  it('$spider.buildCommand resolves to the configured value', async () => {
2028	    const template: RigTemplate = {
2029	      engines: [{ id: 'only', designId: 'seal', givens: { cmd: '$spider.buildCommand' } }],
2030	    };
2031	    const fix = buildFixture({ spider: { buildCommand: 'make build', rigTemplates: { default: template } } });
2032	    const { clerk, spider, stacks } = fix;
2033	
2034	    await clerk.post({ title: 'test', body: 'test' });
2035	    await spider.crawl();
2036	
2037	    const rigs = await rigsBook(stacks).list();
2038	    assert.equal(rigs[0].engines[0].givensSpec.cmd, 'make build');
2039	  });
2040	
2041	  it('$spider.* undefined causes key to be omitted entirely', async () => {
2042	    const template: RigTemplate = {
2043	      engines: [{ id: 'only', designId: 'seal', givens: { cmd: '$spider.testCommand' } }],
2044	    };
2045	    const fix = buildFixture({ spider: { rigTemplates: { default: template } } }); // no testCommand
2046	    const { clerk, spider, stacks } = fix;
2047	
2048	    await clerk.post({ title: 'test', body: 'test' });
2049	    await spider.crawl();
2050	
2051	    const rigs = await rigsBook(stacks).list();
2052	    assert.ok(!('cmd' in rigs[0].engines[0].givensSpec), 'cmd key should be absent when testCommand is not set');
2053	  });
2054	
2055	  it('literal string without $ prefix is passed through unchanged', async () => {
2056	    const template: RigTemplate = {
2057	      engines: [{ id: 'only', designId: 'seal', givens: { role: 'reviewer', count: 5 } }],
2058	    };
2059	    const fix = buildFixture({ spider: { rigTemplates: { default: template } } });
2060	    const { clerk, spider, stacks } = fix;
2061	
2062	    await clerk.post({ title: 'test', body: 'test' });
2063	    await spider.crawl();
2064	
2065	    const rigs = await rigsBook(stacks).list();
2066	    assert.equal(rigs[0].engines[0].givensSpec.role, 'reviewer');
2067	    assert.equal(rigs[0].engines[0].givensSpec.count, 5);
2068	  });
2069	
